import{_ as a,c as t,o as r,a1 as o}from"./chunks/framework.9hXSu8bi.js";const e="/mypatterndocs/static/%E9%A1%B5%E9%9D%A2%E5%B8%83%E5%B1%80.DhmMIl5D.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/开始使用/页面布局.md","filePath":"zh/帮助文档/开始使用/页面布局.md"}'),l={name:"zh/帮助文档/开始使用/页面布局.md"},i=o('<h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><blockquote><p>页面布局是系统的基础框架，分为7个主要区域，涵盖系统名称、导航菜单、主界面等核心模块，帮助用户快速定位和使用各项功能。</p></blockquote><p><img src="'+e+'" alt="" data-fancybox="gallery"></p><h3 id="_1-系统名称" tabindex="-1">1. 系统名称 <a class="header-anchor" href="#_1-系统名称" aria-label="Permalink to &quot;1. 系统名称&quot;">​</a></h3><p>显示当前平台的名称（如“边坡监测预警平台”）。系统名称可以在用户管理-编辑处进行更改。</p><h3 id="_2-用户区域" tabindex="-1">2. 用户区域 <a class="header-anchor" href="#_2-用户区域" aria-label="Permalink to &quot;2. 用户区域&quot;">​</a></h3><p>位于页面右上角，包含用户相关功能：</p><ul><li><strong>消息提醒</strong>：显示未读的系统通知、预警消息等，点击可查看详情。</li><li><strong>用户项目列表</strong>：快速切换当前用户有权限访问的项目。</li><li><strong>头像</strong>：用户自定义头像，鼠标放到头像处可以选择功能，例如查看帮助文档、修改账号、修改密码、退出系统等。</li><li><strong>用户名</strong>：当前登录用户的名称。</li><li><strong>设置</strong>：进入项目配置面，可以修改系统的主题、导航栏模式、界面等。</li></ul><h3 id="_3-菜单列表" tabindex="-1">3. 菜单列表 <a class="header-anchor" href="#_3-菜单列表" aria-label="Permalink to &quot;3. 菜单列表&quot;">​</a></h3><p>左侧导航菜单，点击可切换主功能页面：</p><ul><li><strong>首页</strong>：进入项目总览、地图概览和项目状态监控。</li><li><strong>三维页面</strong>：进入三维监测视图，查看地形、监测点、形变数据等。</li><li><strong>项目管理</strong>：管理项目和子项目的列表及配置。</li><li><strong>预警管理</strong>：查看预警记录、修改预警策略、预警配置和预警人员。</li><li><strong>系统管理</strong>：包括用户管理、角色管理、系统日志查询。</li></ul><h3 id="_4-菜单栏" tabindex="-1">4. 菜单栏 <a class="header-anchor" href="#_4-菜单栏" aria-label="Permalink to &quot;4. 菜单栏&quot;">​</a></h3><p>用户可在此区域快速切换已经打开的不同的菜单。</p><h3 id="_5-页面操作栏" tabindex="-1">5. 页面操作栏 <a class="header-anchor" href="#_5-页面操作栏" aria-label="Permalink to &quot;5. 页面操作栏&quot;">​</a></h3><p>位于页面顶部右侧，提供常用操作按钮：</p><ul><li><strong>刷新</strong>：手动刷新当前页面数据，用于获取最新信息（如监测数据、项目列表等）。</li><li><strong>全屏</strong>：将当前页面切换为全屏显示模式，便于放大查看地图或图表，再次点击退出全屏。</li></ul><h3 id="_6-系统主界面" tabindex="-1">6. 系统主界面 <a class="header-anchor" href="#_6-系统主界面" aria-label="Permalink to &quot;6. 系统主界面&quot;">​</a></h3><p>占据页面中央主要区域，动态显示当前所选功能的具体内容，如项目列表、三维页面、预警记录等。</p><h3 id="_7-菜单列表展开按钮" tabindex="-1">7. 菜单列表展开按钮 <a class="header-anchor" href="#_7-菜单列表展开按钮" aria-label="Permalink to &quot;7. 菜单列表展开按钮&quot;">​</a></h3><p>当菜单列表处于收起状态时，点击可重新展开左侧导航菜单，再次点击收起菜单列表。</p>',20),n=[i];function s(h,_,c,d,p,u){return r(),t("div",null,n)}const b=a(l,[["render",s]]);export{m as __pageData,b as default};
